function NPCData.GetRealmNPCs(realmId: number): {NPC}?
	return NPCData.BY_REALM[realmId]
end

function NPCData.GetImplementedRealms(): {number}
	local out = {}
	for k in pairs(NPCData.BY_REALM) do table.insert(out, k) end
	table.sort(out)
	return out
end

return NPCData
